return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'sv_SE','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Uppdatera tillägget TranslatePress - Multilingual till version %1$s eller högre för att %2$s ska fungera korrekt.','Please install and activate the TranslatePress - Multilingual plugin'=>'Installera och aktivera tillägget TranslatePress - Multilingual','Install & Activate'=>'Installera och aktivera','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Uppdatera TranslatePress - Multilingual till version %2$s eller nyare. Din nuvarande installerade version av TranslatePress - Multilingual är inte längre kompatibel med den aktuella versionen av %1$s.','All TranslatePress functionalities are disabled until then.'=>'Alla TranslatePress-funktioner är inaktiverade tills dess.','Update Now'=>'Uppdatera nu','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Detta tillägg för TranslatePress har migrerats till huvudtillägget och används inte längre. Du kan ta bort det.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> kräver minst PHP-version 5.6.20+ för att köras. Det är <a href="%s">minimikravet för den senaste WordPress-versionen</a>. Kontakta din serveradministratör för att uppdatera din PHP-version.','Advanced'=>'Avancerade','Settings saved.'=>'Inställningarna har sparats.','Are you sure you want to remove this item?'=>'Är du säker på att du vill ta bort detta objekt?','Remove'=>'Ta bort','Add'=>'Lägg till','Select...'=>'Välj...','[%s] Low TranslatePress AI Words'=>'[%s] Lågt antal TranslatePress AI-ord','upgrade your plan or get extra AI Words'=>'uppgradera din plan eller skaffa extra AI-ord','upgrade your plan'=>'uppgradera din plan','TranslatePress AI words are running low on your site.'=>'TranslatePress AI-ord håller på att ta slut på din webbplats.','Current status: %s words remaining'=>'Nuvarande status: %s ord kvar','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'När de återstående AI-orden tar slut pausas den automatiska översättningen via TranslatePress AI.','To continue translating your content, please %1$s over at %2$s'=>'För att fortsätta översätta ditt innehåll, vänligen %1$s på %2$s','Manage Notification: %s'=>'Hantera avisering: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Det finns en ny version av %1$s tillgänglig. %2$sVisa detaljer för version %3$s%4$s eller %5$suppdatera nu%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Det finns en ny version av %1$s tillgänglig. %2$sVisa detaljer för version %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'För att aktivera uppdateringar, vänligen %1$sange din licensnyckel%2$s. Behöver du en licensnyckel? %3$sKöp en nu%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'För att aktivera uppdateringar, gå till %1$slicenssidan%2$s och kontrollera att du har en giltig licens.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'För att aktivera uppdateringar måste din licens förnyas. Gå till sidan %1$sTranslatePress Account%2$s och logga in för att förnya.','You do not have permission to install plugin updates'=>'Du har inte behörighet att installera tilläggsuppdateringar','Error'=>'Fel','Your TranslatePress license key is invalid or missing.'=>'Din licensnyckel för TranslatePress är ogiltig eller saknas.','Your license key expired on %s.'=>'Din licensnyckel upphörde att gälla %s.','Your license key has been disabled.'=>'Din licensnyckel har inaktiverats.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Din licensnyckel är inaktiverad för denna URL. Återaktivera den från <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Hantera webbplatser.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Licensnyckeln matchar inte.</strong> Licensen du angav matchar inte den installerade versionen av TranslatePress.</p><p>Kontrollera att du har installerat rätt version för din licens från ditt TranslatePress-konto.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Om du endast har det kostnadsfria tillägget installerat men har lagt till en betald licens, installera det betalda tillägget från ditt TranslatePress-konto.','Your license key has reached its activation limit.'=>'Din licensnyckel har nått sin aktiveringsgräns.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Uppgradera ditt paket för att lägga till fler webbplatser. %1$sUppgradera nu%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Denna webbplats är redan aktiverad med en kostnadsfri licens. Varje webbplats kan endast använda en kostnadsfri licens.','An error occurred, please try again.'=>'Ett fel inträffade, försök igen.','You have successfully activated your license'=>'Du har aktiverat din licens.','Others'=>'Övriga','Restrict by Language'=>'Begränsa efter språk','Exclude from Language'=>'Exkludera från språk','Restrict element to language'=>'Begränsa element till språk','Show this element only in one language.'=>'Visa detta element endast på ett språk.','Enable translation'=>'Aktivera översättning','Allow translation to the corresponding language only if the content is written in the default language.'=>'Tillåt översättning till motsvarande språk endast om innehållet är skrivet på standardspråket.','Select language'=>'Välj språk','Choose in which language to show this element.'=>'Välj på vilket språk detta element ska visas.','Exclude element from language'=>'Exkludera element från språk','Exclude this element from specific languages.'=>'Exkludera detta element från specifika språk.','Select languages'=>'Välj språk','Choose from which languages to exclude this element.'=>'Välj från vilka språk detta element ska exkluderas.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Detta element kommer fortfarande att vara synligt när du översätter din webbplats via översättningsredigeraren.','The content of this element should be written in the default language.'=>'Innehållet i detta element bör vara skrivet på standardspråket.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> påträffade SQL-fel. <a href="%s" title="View TranslatePress SQL Errors">Kontrollera felen</a>.','Automatic translation has been disabled.'=>'Automatisk översättning har inaktiverats.','Dismiss this notice.'=>'Avfärda denna notis.','Logged errors'=>'Loggade fel','These are the most recent 5 errors logged by TranslatePress:'=>'Detta är de 5 senaste felen som loggats av TranslatePress:','Yes'=>'Ja','Why are these errors occuring'=>'Varför uppstår dessa fel','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Om TranslatePress upptäcker något fel vid körning av frågor i din databas kan den inaktivera funktionen Automatisk översättning för att undvika extra avgifter från Google/DeepL. Automatisk översättning måste aktiveras manuellt efter att du har löst problemen.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'De upptäckta SQL-felen kan uppstå av olika anledningar, bland annat saknade tabeller, saknade behörigheter för SQL-användaren att skapa tabeller eller utföra andra operationer, problem efter migrering av webbplatsen eller ändringar i SQL-serverkonfigurationen.','What you can do in this situation'=>'Vad du kan göra i den här situationen','Plan A.'=>'Plan A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Gå till Inställningar -> TranslatePress -> fliken Allmänt och spara inställningarna. Detta återskapar tabellerna med dina nuvarande SQL-inställningar. Kontrollera att inga fler fel uppstår när du surfar på din webbplats på ett översatt språk. Titta på tidsstämplarna för felen för att säkerställa att du inte ser gamla fel. Endast de 5 senaste felen visas.','Plan B.'=>'Plan B.','If your problem isn\'t solved, try the following steps:'=>'Om ditt problem inte är löst, prova följande steg:','Create a backup of your database'=>'Skapa en säkerhetskopia av din databas','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Skapa en kopia av varje översättningstabell där du stöter på fel. Du kan kopiera tabellen inom samma databas (trp_dictionary_en_us_es_es_COPY till exempel) -- utför detta steg endast om du vill behålla de nuvarande översättningarna','Remove the trouble tables by executing the DROP function on them'=>'Ta bort de problematiska tabellerna genom att köra DROP-funktionen på dem','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Gå till Inställningar -> TranslatePress -> fliken Allmänt och spara inställningarna. Detta återskapar tabellerna med din nuvarande SQL-server.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Kopiera det relevanta innehållet från de duplicerade tabellerna (trp_dictionary_en_us_es_es_COPY till exempel) till den nyskapade tabellen (trp_dictionary_en_us_es_es) -- utför detta steg endast om du vill behålla de nuvarande översättningarna','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Testa för att se om allt fungerar. Om något gick fel kan du återställa säkerhetskopian som du skapade i första steget. Kontrollera att inga fler fel uppstår när du surfar på din webbplats på ett översatt språk. Titta på tidsstämplarna för felen för att säkerställa att du inte ser gamla fel. Endast de 5 senaste felen visas.','Plan C.'=>'Plan C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Om ditt problem fortfarande inte är löst, prova att fråga ditt webbhotell om dina fel. Det vanligaste problemet är saknade behörigheter för SQL-användaren, till exempel behörigheten att skapa tabeller.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Kunde inte installeras. Försök igen från <a href="%s" >tilläggspanelen.</a>','Active'=>'Aktiv','Permission denied.'=>'Åtkomst nekad.','Invalid nonce.'=>'Ogiltig nonce.','Settings scope unknown.'=>'Okänt inställningsomfång.','Legacy disabled.'=>'Äldre läge inaktiverat.','Language Switcher'=>'Språkväxlare','Change language to %s'=>'Ändra språk till %s','Automatic Translation'=>'Automatisk översättning','DeepL'=>'DeepL','Unsupported languages'=>'Ej stödda språk','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Den valda automatiska översättningsmotorn har inte stöd för dessa språk.<br>Du kan fortfarande manuellt översätta sidor på dessa språk med hjälp av översättningsredigeraren.','API key validation failed.'=>'Validering av API-nyckel misslyckades.','API key verification was successful.'=>'Verifiering av API-nyckel lyckades.','Please enter your Google Translate key.'=>'Ange din Google Translate-nyckel.','Please enter your DeepL API key.'=>'Ange din DeepL API-nyckel.','Not TranslatePress onboarding page.'=>'Inte en välkomstsida för TranslatePress.','Step %s does not exist'=>'Steg %s finns inte','Welcome'=>'Välkommen','Add Languages'=>'Lägg till språk','Enable Addons'=>'Aktivera tillägg','Finalize'=>'Slutför','Exit Setup'=>'Avsluta konfiguration','Upgrade'=>'Uppgradera','Nothing here'=>'Inget här','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Din <strong>TranslatePress</strong>-licens saknas eller är ogiltig. <br/>Vänligen %1$sregistrera din kopia%2$s för att aktivera automatisk webbplatsöversättning via TranslatePress AI, premium-tillägg, automatiska uppdateringar och support. Behöver du en licensnyckel? %3$sKöp en nu%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Din <strong>TranslatePress</strong>-licens går ut den %1$s. Vänligen %2$sFörnya din licens%3$s för att fortsätta få tillgång till automatiska översättningar via TP AI, premium-tillägg, produktnedladdningar och automatiska uppdateringar. %4$sFörnya nu%5$s','Error: '=>'Fel: ','Something went wrong, please try again.'=>'Något gick fel, försök igen.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Din <strong>TranslatePress</strong>-licens har upphört att gälla. <br/>Vänligen %1$sFörnya din licens%2$s för att fortsätta få tillgång till automatiska översättningar via TranslatePress AI, premium-tillägg, produktnedladdningar och automatiska uppdateringar. %3$sFörnya nu %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Licensnyckeln stämmer inte överens. Den licens du angav stämmer inte överens med <strong>%1$s</strong>-versionen du har installerad. <br/>Kontrollera att du har installerat rätt version för din licens från ditt %2$sTranslatePress Account%3$s.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Om du endast har det kostnadsfria tillägget installerat men har lagt till en betald licens, installera det betalda tillägget från ditt TranslatePress Account.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Du har nått aktiveringsgränsen för din <strong>%1$s</strong>-licens. <br/>Hantera dina aktiva webbplatser från %2$s ditt konto %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Din licens är inaktiverad för denna URL. Återaktivera den från <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Hantera webbplatser.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s automatisk översättning kräver en aktiv licens. Vänligen %2$sförnya%3$s din licens eller köp en ny %4$shär%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Vänligen %1$sange%2$s din licensnyckel för att aktivera %3$s automatisk översättning.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Du har mindre än 5 000 TranslatePress AI-ord kvar. För att fortsätta översätta din webbplats automatiskt, vänligen %sköp ytterligare AI-ord med rabatt från ditt konto%s.',' Error: '=>' Fel: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Denna webbplats är redan aktiverad med en kostnadsfri licens. Varje webbplats kan endast använda en kostnadsfri licens. Uppgradera till en premiumplan för fler TranslatePress AI-ord från %1$s ditt konto %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Du har ingen giltig licens för <strong>TranslatePress</strong>. %1$sSkaffa en kostnadsfri licens%2$s för att få tillgång till TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NYTT:</strong> Tillägget <strong>Different Domain per Language</strong> är här! Förbättra din globala SEO och skapa en lokal upplevelse med landspecifika domäner som .de eller .fr. Uppgradera till <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> för att få tillgång till det + fler premiumförmåner!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NYTT:</strong> Tillägget <strong>Different Domain per Language</strong> är här! Förbättra din globala SEO och skapa en lokal upplevelse med landspecifika domäner som .de eller .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Läs mer</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Den dagliga kvoten för maskinöversättningstecken har överskridits. Kontrollera sidan <strong>TranslatePress -> <a href="%s">Automatisk översättning</a></strong> för mer information.','Marketing optin'=>'Marknadsföringsopt-in','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Välj att ta emot våra aviseringar om säkerhets- och funktionsuppdateringar, samt icke-känslig diagnostisk spårning.','TranslatePress Preferred User Language'=>'TranslatePress föredraget användarspråk','Preferred language to navigate the site'=>'Föredraget språk för navigering på webbplatsen','The language is automatically set based by the last visited language by the user.'=>'Språket ställs automatiskt in baserat på användarens senast besökta språk.','Always use this language'=>'Använd alltid detta språk','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Genom att markera denna inställning förblir det föredragna språket det som valts ovan, utan möjlighet att ändras i frontend.<br>Detta språk kommer att användas vid olika åtgärder, till exempel när e-post skickas till användaren.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Hej! Det verkar som att du har använt <strong>TranslatePress</strong> ett tag nu för att översätta din webbplats. Det är fantastiskt! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Om du kan avvara några minuter för att betygsätta det på WordPress.org skulle det hjälpa oss mycket (och öka min motivation).','~ Razvan, developer of TranslatePress'=>'~ Razvan, utvecklare av TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Betygsätt TranslatePress på WordPress.org:s pluginsida','Ok, I will gladly help!'=>'Okej, jag hjälper gärna till!','No, thanks.'=>'Nej, tack.','Full Language Names'=>'Fullständiga språknamn','Short Language Names'=>'Korta språknamn','Flags with Full Language Names'=>'Flaggor med fullständiga språknamn','Flags with Short Language Names'=>'Flaggor med korta språknamn','Only Flags'=>'Endast flaggor','Full Language Names No HTML'=>'Fullständiga språknamn utan HTML','Bottom Right'=>'Nedre högra hörnet','Bottom Left'=>'Nedre vänster','Top Right'=>'Övre höger','Top Left'=>'Övre vänster','Dark'=>'Mörk','Light'=>'Ljus','Deactivate'=>'Avaktivera','Activate'=>'Aktivera','Invalid language code. Please try again.'=>'Ogiltig språkkod. Försök igen.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Språkkoder får endast innehålla tecknen A-Z a-z 0-9 - _. Kontrollera dina språkkoder i TranslatePress allmänna inställningar.','Error! Duplicate URL slug values.'=>'Fel! Dubbletter av slug-värden.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Du kan inte välja två språk som har samma <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso-kod</a> men olika formaliteter eftersom det leder till dubbletter av <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang-taggar</a>.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Dubblettspråk upptäckt.<br>Varje språk kan endast läggas till en gång för att säkerställa korrekt översättningshantering.<br> Ändra den dubbletta språkposten och försök igen. ','Current Language'=>'Nuvarande språk','Opposite Language'=>'Motsatt språk','General'=>'Allmänt','Translate Site'=>'Översätt webbplatsen','Addons'=>'Tillägg','License'=>'Licens','Settings'=>'Inställningar','Activate License'=>'Aktivera licens','Pro Features'=>'Pro-funktioner','Need Help?'=>'Behöver du hjälp?','Recent community discussions'=>'Senaste communitydiskussioner','Loading...'=>'Laddar...','Unable to load forum posts'=>'Det gick inte att läsa in foruminlägg','Ask a Question'=>'Ställ en fråga','View All Topics'=>'Visa alla ämnen','by'=>'av','Have a question?'=>'Har du en fråga?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Få hjälp direkt från tilläggsutvecklarna, föreslå förbättringar eller dela din feedback!','Tip for faster help:'=>'Tips för snabbare hjälp:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Inkludera vad du försökte, vad du förväntade dig och vad som hände. Skärmbilder hjälper!','